import { useState,useEffect } from "react";
import { DragDropContext, Droppable, Draggable } from "@hello-pangea/dnd";
import  axios  from 'axios';
export default function Index(){
    const [data,setData] = useState([]);
    const getData = async () => {
        const res = await axios.get("http://localhost:3003");
        setData(res.data);
        
    }
    useEffect(() => {
        console.log(data);
        getData();
    },[]);
    const todo = data.filter(t => t.statut === "todo");
    const inProgress = data.filter(t => t.statut === "in_progress");
    const done = data.filter(t => t.statut === "done");

    const handleDragEnd = (result) => {
    const { destination, source, draggableId } = result;
    if (!destination) return;

    const newTasks = Array.from(data);
    const movedTask = newTasks.find(t => t.id === draggableId);
    movedTask.statut = destination.droppableId;
    setData(newTasks);
    };
    
    return (
        <>
       <center>
                <DragDropContext onDragEnd={handleDragEnd}>
        {['todo', 'in_progress', 'done'].map(col => (
            <Droppable droppableId={col} key={col}>
            {(provided) => (
                <div ref={provided.innerRef} {...provided.droppableProps} className="column">
                <h3>{col === 'todo' ? 'À faire' : col === 'in_progress' ? 'En cours' : 'Terminé'}</h3>
                {data.filter(t => t.statut === col).map((task, index) => (
                    <Draggable key={task.id} draggableId={task.id} index={index}>
                    {(provided) => (
                        <div ref={provided.innerRef} {...provided.draggableProps} {...provided.dragHandleProps} className="task">
                        <h4>{task.titre}</h4>
                        <p>{task.description}</p>
                        </div>
                    )}
                    </Draggable>
                ))}
                {provided.placeholder}
                </div>
            )}
            </Droppable>
        ))}
        </DragDropContext>
       </center>
        </>
    )
}
